import { useEffect, useState } from "react";
import { useParams } from "react-router-dom";
import {
  createTask,
  deleteTask,
  getTasksByProject,
  updateTask,
  updateTaskStatus,
} from "../services/taskService";

function TaskPage() {
  const { id } = useParams(); // 🔥 projectId

  const [tasks, setTasks] = useState([]);
  const [editingTaskId, setEditingTaskId] = useState(null);

  const [formData, setFormData] = useState({
    title: "",
    description: "",
    priority: "medium",
    deadline: "",
    projectId: id,
  });

  // 🔹 Fetch
  const fetchTasks = async () => {
    try {
      const data = await getTasksByProject(id);
      setTasks(data);
    } catch (err) {
      console.error(err);
    }
  };

  useEffect(() => {
    if (id) fetchTasks();
  }, [id]);

  // 🔹 Input
  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  // 🔹 Submit
  const handleSubmit = async (e) => {
    e.preventDefault();

    try {
      if (editingTaskId) {
        await updateTask(editingTaskId, formData);
      } else {
        await createTask({ ...formData, projectId: id });
      }

      setFormData({
        title: "",
        description: "",
        priority: "medium",
        deadline: "",
        projectId: id,
      });

      setEditingTaskId(null);
      fetchTasks();
    } catch (err) {
      console.error(err);
    }
  };

  // 🔹 Delete
  const handleDelete = async (taskId) => {
    await deleteTask(taskId);
    fetchTasks();
  };

  // 🔹 Status
  const handleStatusChange = async (taskId, status) => {
    await updateTaskStatus(taskId, status);

    // update local state (أفضل)
    setTasks((prev) =>
      prev.map((t) =>
        t._id === taskId ? { ...t, status } : t
      )
    );
  };

  // 🔹 Edit
  const handleEdit = (task) => {
    setEditingTaskId(task._id);
    setFormData({
      title: task.title,
      description: task.description,
      priority: task.priority,
      deadline: task.deadline?.slice(0, 10),
      projectId: id,
    });
  };

  return (
    <div style={{ padding: "20px" }}>
      <h1>Tasks - Project</h1>

      {/* FORM */}
      <form onSubmit={handleSubmit}>
        <input
          name="title"
          value={formData.title}
          onChange={handleChange}
          placeholder="Title"
          required
        />

        <textarea
          name="description"
          value={formData.description}
          onChange={handleChange}
          placeholder="Description"
        />

        <select
          name="priority"
          value={formData.priority}
          onChange={handleChange}
        >
          <option value="low">Low</option>
          <option value="medium">Medium</option>
          <option value="high">High</option>
        </select>

        <input
          type="date"
          name="deadline"
          value={formData.deadline}
          onChange={handleChange}
        />

        <button type="submit">
          {editingTaskId ? "Update" : "Create"}
        </button>
      </form>

      {/* LIST */}
      {tasks.map((task) => (
        <div key={task._id} style={{ border: "1px solid #ccc", marginTop: "10px" }}>
          <h3>{task.title}</h3>
          <p>{task.description}</p>

          <p>Status: {task.status}</p>

          <select
            value={task.status}
            onChange={(e) =>
              handleStatusChange(task._id, e.target.value)
            }
          >
            <option value="todo">To do</option>
            <option value="inprogress">In progress</option>
            <option value="done">Done</option>
          </select>

          <br />

          <button onClick={() => handleEdit(task)}>Edit</button>
          <button onClick={() => handleDelete(task._id)}>
            Delete
          </button>
        </div>
      ))}
    </div>
  );
}

export default TaskPage;
